module up_down_counter(rst_clk, reset, up_down, q);

    input rst_clk;
    input reset;
    input up_down;
    output [3:0] q;
    reg [3:0] q;
    initial q = 0;

    always @(posedge rst_clk)
        begin
            if (reset)
                q <= 0;
            else
                q <= (up_down) ? q + 1 : q - 1;
        end

endmodule
